module load_reg(reset_clk, rst, load, d, q);

    input  reset_clk;
    input  rst;
    input  load;
    input  [3:0] d;
    output reg [3:0] q;

    always @(posedge reset_clk or posedge rst) begin
        if (rst)
            q <= 4'b0000;
        else if (load)
            q <= d;
    end

endmodule
